cd /tmp/sv-d1d38ca2a09e469e93d715dff56576e8/symbols

# Use readelf/nm to find actual function names for the problematic addresses
# by looking up what function contains those addresses
for addr in 0x2f4b20 0x2f4c84; do
  echo "=== Looking up $addr ==="
  # Get all function symbols sorted by address, find the one containing our address
  aarch64-linux-gnu-nm -C --defined-only -n libmonosgen-2.0.so.debug 2>/dev/null | \
    awk -v target="$addr" '
      BEGIN { gsub(/^0x/, "", target); target = tolower(target) }
      /^[0-9a-f]+ [tTwW]/ {
        addr = $1; name = $3;
        if (addr <= target && addr != "") { last_addr = addr; last_name = name }
        if (addr > target && !found) { found = 1; print "  " target " is in: " last_name " (at 0x" last_addr ")" }
      }
    '
done

